#include<bits/stdc++.h>
using namespace std;

vector<int> distribute(vector<int> &arr) {
	int n = arr.size();
	multiset<int> first, second;
	first.insert(arr[0]);
	second.insert(arr[1]);

	for(int i=2;i<n;i++) {
		int g1 = distance(first.upper_bound(arr[i]), first.end()) ;
		int g2 = distance(second.upper_bound(arr[i]), second.end());
		if(g1 >= g2) {
			first.insert(arr[i]);
		}
		else {
			second.insert(arr[i]);
		}
	}
	vector<int> ans;
	for(auto &x: first) {
		ans.push_back(x);
	}
	for(auto &x: second) {
		ans.push_back(x);
	}
	return ans;
}


int main() {
	int n;
	cin >> n;
	vector<int> arr(n);
	for(int i=0;i<n;i++) {
		cin >> arr[i];
	}

	vector<int> ans = distribute(arr);
	for(auto &x: ans) {
		cout << x << " ";
	}
	cout << "\n";
	return 0;
}

/*
N = 8
Arr[] = 3 6 4 1 7 2 5 8

First = 3 7 2 5 8
Second = 6 4 1
Ans = 2 3 5 7 8 1 4 6
*/
