public class CommonPrefixPairs {
    public static int countCommonPrefixPairs(String[] input) {
        int count = 0;
        Set<String> commonPrefixes = new HashSet<>();

        // Iterate through each pair of strings
        for (int i = 0; i < input.length - 1; i++) {
            for (int j = i + 1; j < input.length; j++) {
                // Find the length of the common prefix
                int prefixLength = commonPrefixLength(input[i], input[j]);
                // If the prefix length is greater than 0, add the prefix to the HashSet
                if (prefixLength > 0) {
                    commonPrefixes.add(input[i].substring(0, prefixLength));
                }
            }
        }

        // Print the common prefixes
        System.out.println("Common Prefixes:");
        for (String prefix : commonPrefixes) {
            System.out.println(prefix);
        }

        // Return the count of unique common prefix pairs
        return commonPrefixes.size();
    }

    // Function to find the length of the common prefix between two strings
    private static int commonPrefixLength(String str1, String str2) {
        int minLength = Math.min(str1.length(), str2.length());
        int prefixLength = 0;

        // Iterate through the characters of both strings
        for (int i = 0; i < minLength; i++) {
            if (str1.charAt(i) == str2.charAt(i)) {
                prefixLength++;
            } else {
                break; // Stop when a character mismatch is found
            }
        }

        return prefixLength;
    }

